class XCORE(archist.core.Arch):
    name = "XCORE"
    ks = None
    cs = capstone.CS_ARCH_XCORE
    uc = None
    ql = None

    @classmethod
    def Cs(
        cls,
        endian:archist.core.Endian|str = archist.core.LITTLE_ENDIAN,
        
        
    ):
        return cls._Cs(
            mode=archist.core.NO_MODES,
            endian=endian,
            
        )


